# Iterate directly over list elements
for fruit in ["apple", "banana", "cherry"]:
    print(fruit)

# range(stop) - generates 0 to 4
for i in range(5):
    print(i)          # 0 1 2 3 4

# range(start, stop, step)
for i in range(2, 10, 3):
    print(i)          # 2 5 8

# break - exit loop immediately
for n in range(10):
    if n == 5:
        break

# continue - skip current iteration step
for n in range(5):
    if n % 2 == 0:
        continue
    print(n)          # 1 3

# for-else - executes only if loop completes normally
for n in range(5):
    if n == 10:
        break
else:
    print("no break")  # runs since 10 is not hit

# pass - syntactic placeholder/no-op
def future_func():
    pass
